import React, { useState } from 'react';
import { Calendar, Clock, User, Mail, Phone, FileText, CheckCircle } from 'lucide-react';
import { Button } from './ui/button';
import { Input } from './ui/input';
import { Label } from './ui/label';
import { Textarea } from './ui/textarea';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from './ui/card';
import { Calendar as CalendarComponent } from './ui/calendar';
import { Popover, PopoverContent, PopoverTrigger } from './ui/popover';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from './ui/select';
import { format } from 'date-fns';
import { es } from 'date-fns/locale';
import { guardarCita, horariosDisponibles } from '../data/mock';
import { toast } from 'sonner';
import emailjs from '@emailjs/browser';

const CitasSection = () => {
  const [formData, setFormData] = useState({
    nombre: '',
    email: '',
    telefono: '',
    servicio: '',
    fecha: null,
    hora: '',
    mensaje: ''
  });
  const [isSubmitted, setIsSubmitted] = useState(false);

  const handleInputChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!formData.nombre || !formData.email || !formData.telefono || !formData.fecha || !formData.hora || !formData.servicio) {
      toast.error('Por favor completa todos los campos requeridos');
      return;
    }

    try {
      // Preparar datos de la cita
      const cita = guardarCita({
        ...formData,
        fecha: format(formData.fecha, 'yyyy-MM-dd')
      });

      // Enviar email a contacto@logisticamigratoriafs.com
      const templateParams = {
        from_name: formData.nombre,
        from_email: formData.email,
        phone: formData.telefono,
        service: formData.servicio,
        date: format(formData.fecha, 'PPP', { locale: es }),
        time: formData.hora,
        message: formData.mensaje || 'Sin mensaje adicional',
        to_email: 'contacto@logisticamigratoriafs.com'
      };

      // Usar EmailJS para enviar el correo
      await emailjs.send(
        'service_default', // Service ID (configurar en EmailJS)
        'template_citas', // Template ID (configurar en EmailJS)
        templateParams,
        'tu_public_key' // Public Key (configurar en EmailJS)
      );

      console.log('Cita agendada y enviada por email:', cita);
      setIsSubmitted(true);
      toast.success('¡Cita agendada exitosamente! Te contactaremos pronto.');

      setTimeout(() => {
        setIsSubmitted(false);
        setFormData({
          nombre: '',
          email: '',
          telefono: '',
          servicio: '',
          fecha: null,
          hora: '',
          mensaje: ''
        });
      }, 5000);
    } catch (error) {
      console.error('Error al enviar cita:', error);
      
      // Fallback: abrir cliente de correo predeterminado
      const mailtoLink = `mailto:contacto@logisticamigratoriafs.com?subject=${encodeURIComponent('Nueva Cita Agendada')}&body=${encodeURIComponent(
        `NUEVA CITA AGENDADA\n\nNombre: ${formData.nombre}\nEmail: ${formData.email}\nTeléfono: ${formData.telefono}\nServicio: ${formData.servicio}\nFecha: ${format(formData.fecha, 'PPP', { locale: es })}\nHora: ${formData.hora}\n\nMensaje:\n${formData.mensaje || 'Sin mensaje adicional'}`
      )}`;
      window.location.href = mailtoLink;
      
      toast.info('Se abrirá tu cliente de correo para enviar la cita');
    }
  };

  if (isSubmitted) {
    return (
      <section id="citas" className="py-20 bg-gradient-to-br from-emerald-50 to-white">
        <div className="max-w-2xl mx-auto px-4">
          <Card className="border-emerald-200 shadow-2xl">
            <CardContent className="p-12 text-center">
              <div className="w-20 h-20 bg-emerald-100 rounded-full flex items-center justify-center mx-auto mb-6">
                <CheckCircle className="text-emerald-600" size={48} />
              </div>
              <h3 className="text-3xl font-bold text-slate-900 mb-4">¡Cita Agendada!</h3>
              <p className="text-lg text-slate-600 mb-2">
                Gracias por confiar en nosotros. Hemos recibido tu solicitud de cita.
              </p>
              <p className="text-slate-600">
                Te contactaremos pronto para confirmar los detalles.
              </p>
              <div className="mt-8 p-6 bg-slate-50 rounded-lg text-left">
                <h4 className="font-bold text-slate-900 mb-3">Resumen de tu cita:</h4>
                <div className="space-y-2 text-sm text-slate-700">
                  <p><strong>Nombre:</strong> {formData.nombre}</p>
                  <p><strong>Email:</strong> {formData.email}</p>
                  <p><strong>Servicio:</strong> {formData.servicio}</p>
                  <p><strong>Fecha:</strong> {format(formData.fecha, 'PPP', { locale: es })}</p>
                  <p><strong>Hora:</strong> {formData.hora}</p>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
      </section>
    );
  }

  return (
    <section id="citas" className="py-20 bg-gradient-to-br from-green-50 to-white">
      <div className="max-w-4xl mx-auto px-4">
        {/* Header */}
        <div className="text-center mb-12">
          <span className="text-green-600 font-semibold text-sm uppercase tracking-wider">Agenda tu Cita</span>
          <h2 className="text-4xl md:text-5xl font-bold text-blue-900 mt-3 mb-4">
            Consulta Gratuita
          </h2>
          <p className="text-xl text-slate-600 max-w-2xl mx-auto">
            Agenda una consulta sin costo. Evaluaremos tu caso y te brindaremos la mejor asesoría.
          </p>
        </div>

        <Card className="shadow-2xl border-slate-200">
          <CardHeader className="bg-gradient-to-r from-slate-50 to-emerald-50">
            <CardTitle className="text-2xl">Completa el Formulario</CardTitle>
            <CardDescription className="text-base">
              Selecciona la fecha y hora que mejor te convenga. Te contactaremos para confirmar.
            </CardDescription>
          </CardHeader>
          <CardContent className="p-8">
            <form onSubmit={handleSubmit} className="space-y-6">
              {/* Personal Info */}
              <div className="grid md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <Label htmlFor="nombre" className="text-slate-900 font-medium">
                    <User className="inline mr-2" size={16} />
                    Nombre Completo *
                  </Label>
                  <Input
                    id="nombre"
                    name="nombre"
                    value={formData.nombre}
                    onChange={handleInputChange}
                    placeholder="Juan Pérez"
                    required
                    className="border-slate-300 focus:border-emerald-500"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="email" className="text-slate-900 font-medium">
                    <Mail className="inline mr-2" size={16} />
                    Email *
                  </Label>
                  <Input
                    id="email"
                    name="email"
                    type="email"
                    value={formData.email}
                    onChange={handleInputChange}
                    placeholder="juan@ejemplo.com"
                    required
                    className="border-slate-300 focus:border-emerald-500"
                  />
                </div>
              </div>

              <div className="grid md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <Label htmlFor="telefono" className="text-slate-900 font-medium">
                    <Phone className="inline mr-2" size={16} />
                    Teléfono *
                  </Label>
                  <Input
                    id="telefono"
                    name="telefono"
                    type="tel"
                    value={formData.telefono}
                    onChange={handleInputChange}
                    placeholder="+123 456 7890"
                    required
                    className="border-slate-300 focus:border-emerald-500"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="servicio" className="text-slate-900 font-medium">
                    <FileText className="inline mr-2" size={16} />
                    Servicio de Interés *
                  </Label>
                  <Select value={formData.servicio} onValueChange={(value) => setFormData({ ...formData, servicio: value })}>
                    <SelectTrigger className="border-slate-300 focus:border-emerald-500">
                      <SelectValue placeholder="Selecciona un servicio" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="visa-turismo-usa">Visa de Turismo USA</SelectItem>
                      <SelectItem value="visa-turismo-canada">Visa de Turismo Canadá</SelectItem>
                      <SelectItem value="residencia-permanente-usa">Residencia Permanente USA</SelectItem>
                      <SelectItem value="residencia-permanente-canada">Residencia Permanente Canadá</SelectItem>
                      <SelectItem value="reagrupacion-familiar-usa">Reagrupación Familiar USA</SelectItem>
                      <SelectItem value="reagrupacion-familiar-canada">Reagrupación Familiar Canadá</SelectItem>
                      <SelectItem value="consulta-general">Consulta General</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>

              {/* Date and Time */}
              <div className="grid md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <Label className="text-slate-900 font-medium">
                    <Calendar className="inline mr-2" size={16} />
                    Fecha Preferida *
                  </Label>
                  <Popover>
                    <PopoverTrigger asChild>
                      <Button
                        variant="outline"
                        className="w-full justify-start text-left font-normal border-slate-300 focus:border-emerald-500"
                      >
                        <Calendar className="mr-2 h-4 w-4" />
                        {formData.fecha ? format(formData.fecha, 'PPP', { locale: es }) : 'Selecciona una fecha'}
                      </Button>
                    </PopoverTrigger>
                    <PopoverContent className="w-auto p-0" align="start">
                      <CalendarComponent
                        mode="single"
                        selected={formData.fecha}
                        onSelect={(date) => setFormData({ ...formData, fecha: date })}
                        disabled={(date) => date < new Date()}
                        initialFocus
                      />
                    </PopoverContent>
                  </Popover>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="hora" className="text-slate-900 font-medium">
                    <Clock className="inline mr-2" size={16} />
                    Hora Preferida *
                  </Label>
                  <Select value={formData.hora} onValueChange={(value) => setFormData({ ...formData, hora: value })}>
                    <SelectTrigger className="border-slate-300 focus:border-emerald-500">
                      <SelectValue placeholder="Selecciona una hora" />
                    </SelectTrigger>
                    <SelectContent>
                      {horariosDisponibles.map((hora) => (
                        <SelectItem key={hora} value={hora}>{hora}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              {/* Message */}
              <div className="space-y-2">
                <Label htmlFor="mensaje" className="text-slate-900 font-medium">
                  Mensaje Adicional (Opcional)
                </Label>
                <Textarea
                  id="mensaje"
                  name="mensaje"
                  value={formData.mensaje}
                  onChange={handleInputChange}
                  placeholder="Cuéntanos brevemente sobre tu caso o cualquier pregunta que tengas..."
                  rows={4}
                  className="border-slate-300 focus:border-emerald-500"
                />
              </div>

              {/* Submit Button */}
              <Button 
                type="submit"
                className="w-full bg-green-600 hover:bg-green-700 text-white py-6 text-lg shadow-lg hover:shadow-xl transition-all"
              >
                Agendar Cita Gratuita
              </Button>
            </form>
          </CardContent>
        </Card>
      </div>
    </section>
  );
};

export default CitasSection;
