import React, { useState } from 'react';
import { MapPin, Send, MessageCircle, Mail } from 'lucide-react';
import { Button } from './ui/button';
import { Input } from './ui/input';
import { Label } from './ui/label';
import { Textarea } from './ui/textarea';
import { Card, CardContent } from './ui/card';
import { toast } from 'sonner';
import emailjs from '@emailjs/browser';

const ContactoSection = () => {
  const [formData, setFormData] = useState({
    nombre: '',
    email: '',
    telefono: '',
    asunto: '',
    mensaje: ''
  });

  const handleInputChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!formData.nombre || !formData.email || !formData.mensaje) {
      toast.error('Por favor completa todos los campos requeridos');
      return;
    }

    try {
      // Enviar email directamente a contacto@logisticamigratoriafs.com
      const templateParams = {
        from_name: formData.nombre,
        from_email: formData.email,
        phone: formData.telefono,
        subject: formData.asunto || 'Nuevo mensaje de contacto',
        message: formData.mensaje,
        to_email: 'contacto@logisticamigratoriafs.com'
      };

      // Usar EmailJS para enviar el correo
      // Nota: Necesitas configurar EmailJS con tus credenciales
      await emailjs.send(
        'service_default', // Service ID (configurar en EmailJS)
        'template_contact', // Template ID (configurar en EmailJS)
        templateParams,
        'tu_public_key' // Public Key (configurar en EmailJS)
      );

      toast.success('¡Mensaje enviado exitosamente! Te responderemos pronto.');
      
      // Limpiar formulario
      setFormData({
        nombre: '',
        email: '',
        telefono: '',
        asunto: '',
        mensaje: ''
      });
    } catch (error) {
      console.error('Error al enviar email:', error);
      
      // Fallback: abrir cliente de correo predeterminado
      const mailtoLink = `mailto:contacto@logisticamigratoriafs.com?subject=${encodeURIComponent(formData.asunto || 'Contacto desde sitio web')}&body=${encodeURIComponent(
        `Nombre: ${formData.nombre}\nEmail: ${formData.email}\nTeléfono: ${formData.telefono}\n\nMensaje:\n${formData.mensaje}`
      )}`;
      window.location.href = mailtoLink;
      
      toast.info('Se abrirá tu cliente de correo para enviar el mensaje');
    }
  };

  const handleWhatsAppCanada = () => {
    const mensaje = encodeURIComponent('Hola, me gustaría recibir información sobre sus servicios migratorios.');
    window.open(`https://wa.me/14389352069?text=${mensaje}`, '_blank');
  };

  const handleWhatsAppMexico = () => {
    const mensaje = encodeURIComponent('Hola, me gustaría recibir información sobre sus servicios migratorios.');
    window.open(`https://wa.me/525531415183?text=${mensaje}`, '_blank');
  };

  return (
    <section id="contacto" className="py-20 bg-gradient-to-br from-slate-50 to-white">
      <div className="max-w-7xl mx-auto px-4">
        {/* Header */}
        <div className="text-center mb-16">
          <span className="text-green-600 font-semibold text-sm uppercase tracking-wider">Contáctanos</span>
          <h2 className="text-4xl md:text-5xl font-bold text-blue-900 mt-3 mb-4">
            Estamos Aquí Para Ayudarte
          </h2>
          <p className="text-xl text-slate-600 max-w-2xl mx-auto">
            Ponte en contacto con nosotros. Responderemos todas tus consultas a la brevedad.
          </p>
        </div>

        <div className="grid lg:grid-cols-3 gap-8">
          {/* Contact Info */}
          <div className="lg:col-span-1 space-y-6">
            <Card className="border-green-200 hover:shadow-xl transition-shadow">
              <CardContent className="p-6">
                <div className="w-12 h-12 bg-green-100 rounded-lg flex items-center justify-center mb-4">
                  <MapPin className="text-green-700" size={24} />
                </div>
                <h3 className="font-bold text-blue-900 text-lg mb-2">Ubicación</h3>
                <a 
                  href="https://maps.google.com/?q=Montecito+38+Nápoles+Benito+Juárez+03810+Ciudad+de+México+CDMX" 
                  target="_blank" 
                  rel="noopener noreferrer"
                  className="text-slate-600 hover:text-green-700 transition-colors block"
                >
                  Montecito 38, Nápoles<br />
                  Benito Juárez, 03810<br />
                  Ciudad de México, CDMX<br />
                  Piso 28, Oficina 16<br />
                  <span className="text-green-600 text-sm mt-2 inline-block">📍 Ver en Google Maps</span>
                </a>
              </CardContent>
            </Card>

            <Card className="border-green-200 hover:shadow-xl transition-shadow">
              <CardContent className="p-6">
                <div className="w-12 h-12 bg-green-100 rounded-lg flex items-center justify-center mb-4">
                  <Mail className="text-green-700" size={24} />
                </div>
                <h3 className="font-bold text-blue-900 text-lg mb-2">Email</h3>
                <a 
                  href="mailto:contacto@logisticamigratoriafs.com" 
                  className="text-slate-600 hover:text-green-700 transition-colors break-all"
                >
                  contacto@logisticamigratoriafs.com
                </a>
              </CardContent>
            </Card>

            {/* WhatsApp Buttons */}
            <div className="space-y-3">
              <Button
                onClick={handleWhatsAppCanada}
                className="w-full bg-green-600 hover:bg-green-700 text-white py-6 text-lg shadow-lg hover:shadow-xl transition-all"
              >
                <MessageCircle className="mr-2" size={20} />
                WhatsApp Canadá
              </Button>
              <Button
                onClick={handleWhatsAppMexico}
                className="w-full bg-green-600 hover:bg-green-700 text-white py-6 text-lg shadow-lg hover:shadow-xl transition-all"
              >
                <MessageCircle className="mr-2" size={20} />
                WhatsApp México
              </Button>
            </div>
          </div>

          {/* Contact Form */}
          <div className="lg:col-span-2">
            <Card className="shadow-2xl border-slate-200">
              <CardContent className="p-8">
                <h3 className="text-2xl font-bold text-slate-900 mb-6">Envíanos un Mensaje</h3>
                <form onSubmit={handleSubmit} className="space-y-6">
                  <div className="grid md:grid-cols-2 gap-6">
                    <div className="space-y-2">
                      <Label htmlFor="nombre" className="text-slate-900 font-medium">
                        Nombre Completo *
                      </Label>
                      <Input
                        id="nombre"
                        name="nombre"
                        value={formData.nombre}
                        onChange={handleInputChange}
                        placeholder="Juan Pérez"
                        required
                        className="border-slate-300 focus:border-emerald-500"
                      />
                    </div>

                    <div className="space-y-2">
                      <Label htmlFor="email" className="text-slate-900 font-medium">
                        Email *
                      </Label>
                      <Input
                        id="email"
                        name="email"
                        type="email"
                        value={formData.email}
                        onChange={handleInputChange}
                        placeholder="juan@ejemplo.com"
                        required
                        className="border-slate-300 focus:border-emerald-500"
                      />
                    </div>
                  </div>

                  <div className="grid md:grid-cols-2 gap-6">
                    <div className="space-y-2">
                      <Label htmlFor="telefono" className="text-slate-900 font-medium">
                        Teléfono
                      </Label>
                      <Input
                        id="telefono"
                        name="telefono"
                        type="tel"
                        value={formData.telefono}
                        onChange={handleInputChange}
                        placeholder="+123 456 7890"
                        className="border-slate-300 focus:border-emerald-500"
                      />
                    </div>

                    <div className="space-y-2">
                      <Label htmlFor="asunto" className="text-slate-900 font-medium">
                        Asunto
                      </Label>
                      <Input
                        id="asunto"
                        name="asunto"
                        value={formData.asunto}
                        onChange={handleInputChange}
                        placeholder="Consulta sobre visa de trabajo"
                        className="border-slate-300 focus:border-emerald-500"
                      />
                    </div>
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="mensaje" className="text-slate-900 font-medium">
                      Mensaje *
                    </Label>
                    <Textarea
                      id="mensaje"
                      name="mensaje"
                      value={formData.mensaje}
                      onChange={handleInputChange}
                      placeholder="Cuéntanos en qué podemos ayudarte..."
                      rows={6}
                      required
                      className="border-slate-300 focus:border-emerald-500"
                    />
                  </div>

                  <Button 
                    type="submit"
                    className="w-full bg-emerald-600 hover:bg-emerald-700 text-white py-6 text-lg shadow-lg hover:shadow-xl transition-all"
                  >
                    <Send className="mr-2" size={20} />
                    Enviar Mensaje
                  </Button>
                </form>
              </CardContent>
            </Card>
          </div>
        </div>
      </div>
    </section>
  );
};

export default ContactoSection;
