import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Menu, X, Clock } from 'lucide-react';
import { Button } from './ui/button';

const Header = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollToSection = (sectionId) => {
    const element = document.getElementById(sectionId);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth', block: 'start' });
      setIsMobileMenuOpen(false);
    }
  };

  return (
    <>
      {/* Top Bar */}
      <div className="bg-gradient-to-r from-blue-900 to-blue-800 text-white py-2 px-4">
        <div className="max-w-7xl mx-auto flex flex-wrap justify-center items-center text-sm gap-2">
          <div className="flex items-center gap-2">
            <Clock size={14} />
            <span>Lun - Vie: 09:00 - 20:00</span>
          </div>
        </div>
      </div>

      {/* Main Header */}
      <header 
        className={`sticky top-0 z-50 transition-all duration-300 ${
          isScrolled 
            ? 'bg-white/95 backdrop-blur-md shadow-lg' 
            : 'bg-white'
        }`}
      >
        <div className="max-w-7xl mx-auto px-4 py-4">
          <div className="flex justify-between items-center">
            {/* Logo */}
            <Link to="/" className="flex items-center gap-3 group">
              <img 
                src="https://customer-assets.emergentagent.com/job_gestoria-migratorio/artifacts/zgsp5nk6_WhatsApp%20Image%202026-04-06%20at%2013.10.47.jpeg" 
                alt="Logística Migratoria FS"
                className="h-24 w-auto object-contain group-hover:scale-105 transition-transform"
              />
            </Link>

            {/* Desktop Navigation */}
            <nav className="hidden md:flex items-center gap-8">
              <button onClick={() => scrollToSection('inicio')} className="text-blue-900 hover:text-green-600 font-medium transition-colors">
                Inicio
              </button>
              <button onClick={() => scrollToSection('servicios')} className="text-blue-900 hover:text-green-600 font-medium transition-colors">
                Servicios
              </button>
              <button onClick={() => scrollToSection('nosotros')} className="text-blue-900 hover:text-green-600 font-medium transition-colors">
                Nosotros
              </button>
              <button onClick={() => scrollToSection('testimonios')} className="text-blue-900 hover:text-green-600 font-medium transition-colors">
                Testimonios
              </button>
              <button onClick={() => scrollToSection('contacto')} className="text-blue-900 hover:text-green-600 font-medium transition-colors">
                Contacto
              </button>
              <Button 
                onClick={() => scrollToSection('citas')}
                className="bg-gradient-to-r from-green-600 to-green-500 hover:from-green-700 hover:to-green-600 text-white shadow-lg hover:shadow-xl transition-all"
              >
                Agendar Cita
              </Button>
            </nav>

            {/* Mobile Menu Button */}
            <button
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              className="md:hidden p-2 text-blue-900 hover:text-green-600 transition-colors"
            >
              {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>

          {/* Mobile Navigation */}
          {isMobileMenuOpen && (
            <nav className="md:hidden mt-4 pb-4 border-t border-slate-200 pt-4 space-y-3">
              <button onClick={() => scrollToSection('inicio')} className="block w-full text-left px-4 py-2 text-blue-900 hover:bg-green-50 hover:text-green-700 rounded-lg transition-colors">
                Inicio
              </button>
              <button onClick={() => scrollToSection('servicios')} className="block w-full text-left px-4 py-2 text-blue-900 hover:bg-green-50 hover:text-green-700 rounded-lg transition-colors">
                Servicios
              </button>
              <button onClick={() => scrollToSection('nosotros')} className="block w-full text-left px-4 py-2 text-blue-900 hover:bg-green-50 hover:text-green-700 rounded-lg transition-colors">
                Nosotros
              </button>
              <button onClick={() => scrollToSection('testimonios')} className="block w-full text-left px-4 py-2 text-blue-900 hover:bg-green-50 hover:text-green-700 rounded-lg transition-colors">
                Testimonios
              </button>
              <button onClick={() => scrollToSection('contacto')} className="block w-full text-left px-4 py-2 text-blue-900 hover:bg-green-50 hover:text-green-700 rounded-lg transition-colors">
                Contacto
              </button>
              <Button 
                onClick={() => scrollToSection('citas')}
                className="w-full bg-gradient-to-r from-green-600 to-green-500 hover:from-green-700 hover:to-green-600 text-white"
              >
                Agendar Cita
              </Button>
            </nav>
          )}
        </div>
      </header>
    </>
  );
};

export default Header;
