import React from "react";
import "./App.css";
import { BrowserRouter, Routes, Route } from "react-router-dom";
import { Toaster } from "./components/ui/sonner";
import Header from "./components/Header";
import Footer from "./components/Footer";
import HeroSection from "./components/HeroSection";
import ServiciosSection from "./components/ServiciosSection";
import NosotrosSection from "./components/NosotrosSection";
import TestimoniosSection from "./components/TestimoniosSection";
import CitasSection from "./components/CitasSection";
import ContactoSection from "./components/ContactoSection";
import { MessageCircle } from "lucide-react";

const Home = () => {
  const handleWhatsAppCanada = () => {
    const mensaje = encodeURIComponent('Hola, me gustaría recibir información sobre sus servicios migratorios.');
    window.open(`https://wa.me/14389352069?text=${mensaje}`, '_blank');
  };

  const handleWhatsAppMexico = () => {
    const mensaje = encodeURIComponent('Hola, me gustaría recibir información sobre sus servicios migratorios.');
    window.open(`https://wa.me/525531415183?text=${mensaje}`, '_blank');
  };

  return (
    <div className="min-h-screen">
      <Header />
      <main>
        <HeroSection />
        <ServiciosSection />
        <NosotrosSection />
        <TestimoniosSection />
        <CitasSection />
        <ContactoSection />
      </main>
      <Footer />
      
      {/* WhatsApp Floating Buttons */}
      <div className="fixed bottom-6 right-6 z-50 flex flex-col gap-3">
        <button
          onClick={handleWhatsAppCanada}
          className="group bg-green-600 hover:bg-green-700 text-white px-4 py-3 rounded-full shadow-2xl hover:shadow-green-500/50 flex items-center gap-2 transition-all hover:scale-105"
          aria-label="Chat por WhatsApp Canadá"
        >
          <MessageCircle size={24} />
          <span className="font-medium text-sm">WhatsApp Canadá</span>
        </button>
        <button
          onClick={handleWhatsAppMexico}
          className="group bg-green-600 hover:bg-green-700 text-white px-4 py-3 rounded-full shadow-2xl hover:shadow-green-500/50 flex items-center gap-2 transition-all hover:scale-105"
          aria-label="Chat por WhatsApp México"
        >
          <MessageCircle size={24} />
          <span className="font-medium text-sm">WhatsApp México</span>
        </button>
      </div>

      <Toaster position="top-center" richColors />
    </div>
  );
};

function App() {
  return (
    <div className="App">
      <BrowserRouter>
        <Routes>
          <Route path="/" element={<Home />} />
        </Routes>
      </BrowserRouter>
    </div>
  );
}

export default App;
